import{_ as o,o as t,c as a,ag as d}from"./chunks/framework.DZKik_R9.js";const u=JSON.parse('{"title":"Aperçu de l’API (abtest-solution)","description":"","frontmatter":{},"headers":[],"relativePath":"reference/api-overview.md","filePath":"reference/api-overview.md"}'),c={name:"reference/api-overview.md"};function n(s,e,r,i,p,l){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="apercu-de-l-api-abtest-solution" tabindex="-1">Aperçu de l’API (abtest-solution) <a class="header-anchor" href="#apercu-de-l-api-abtest-solution" aria-label="Permalink to &quot;Aperçu de l’API (abtest-solution)&quot;">​</a></h1><p>Service <strong><code>apps/api</code></strong> (Express). Chemins exacts dans <code>server.ts</code> du dépôt.</p><h2 id="principaux-endpoints" tabindex="-1">Principaux endpoints <a class="header-anchor" href="#principaux-endpoints" aria-label="Permalink to &quot;Principaux endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Corps / usage</th><th>Réponse (idée)</th></tr></thead><tbody><tr><td><code>POST /api/evaluate</code></td><td><code>campaignId</code> (<strong>nombre</strong> 10000–99999), <code>context</code>, optionnel <code>simulation</code> (<code>variationId</code> <strong>nombre</strong>).</td><td>Objet <strong><code>campaign</code></strong>, <strong><code>variation</code></strong> (tel que la config : champs <code>id</code>, <code>name</code>, <code>trafficAllocation</code>, chemins d’assets si front, <strong><code>featureFlags</code></strong> optionnel pour le <strong>backend</strong> / BFF), <code>reason</code>, <code>matchedSegmentIds</code>, <code>campaignSegments</code>, <strong><code>diagnostics</code></strong> (<code>hadAssignedVariationInRequest</code>, <code>resolvedBySticky</code>).</td></tr><tr><td><code>POST /api/evaluate/segment-diagnostics</code></td><td><code>campaignId</code>, <code>context</code>, <strong><code>simulation</code> obligatoire</strong> (objet JSON, peut être <code>{}</code>). Réservé au mode lab / diagnostic (ex. UI admin).</td><td>Par segment rattaché à la campagne : <code>id</code>, <code>name</code>, <code>matches</code>, <code>breakdown</code> (arbre critère attendu / valeur actuelle, aligné sur le moteur).</td></tr><tr><td><code>GET /api/consent-config</code></td><td>—</td><td><code>stored</code> / <code>effective</code> : <strong>domain</strong> (site), cookie <code>name</code>/<code>value</code>, garde-fou, <code>envOverrides</code>.</td></tr><tr><td><code>PUT /api/consent-config</code></td><td><strong><code>domain</code></strong> (obligatoire, non vide), <strong><code>acceptanceCookie</code></strong> <code>{ name, value }</code></td><td>Écrit <code>consent-config.json</code> ; réponse alignée sur <code>GET</code>.</td></tr><tr><td><code>GET</code> / <code>POST</code> / <code>PUT</code> / <code>DELETE</code>… sous <code>/api/campaigns</code>, <code>/api/segments</code>, etc.</td><td>Selon route</td><td>Utilisés par l’UI ; persistance fichiers via <code>storage-fs</code>.</td></tr></tbody></table><h2 id="post-api-evaluate-—-objet-variation" tabindex="-1"><code>POST /api/evaluate</code> — objet <code>variation</code> <a class="header-anchor" href="#post-api-evaluate-—-objet-variation" aria-label="Permalink to &quot;`POST /api/evaluate` — objet `variation`&quot;">​</a></h2><p>L’API renvoie la <strong>variation choisie</strong> telle que chargée depuis le stockage (fichiers sous <strong><code>abtest-campaigns-segments</code></strong>). Les champs <strong><code>jsPath</code></strong> / <strong><code>cssPath</code></strong> / chemins <strong><code>shared*</code></strong> concernent surtout les campagnes <strong><code>frontend</code></strong>. Pour une campagne <strong><code>backend</code></strong>, l’intégration attendue côté hôte est de consommer notamment <strong><code>variation.featureFlags</code></strong> (objet <code>string → boolean</code> défini dans le <code>config.json</code> de la campagne) après l’appel serveur à <strong><code>/api/evaluate</code></strong>.</p><h2 id="post-api-evaluate-—-champ-reason" tabindex="-1"><code>POST /api/evaluate</code> — champ <code>reason</code> <a class="header-anchor" href="#post-api-evaluate-—-champ-reason" aria-label="Permalink to &quot;`POST /api/evaluate` — champ `reason`&quot;">​</a></h2><p>Valeurs possibles (moteur <code>packages/core</code>) : <code>by_bucket</code>, <code>by_sticky_assignment</code>, <code>forced_simulation</code>, <code>campaign_not_running</code>, <code>no_matching_segment</code>, <code>no_variation</code>, <code>consent_required</code>.</p><h2 id="post-api-evaluate-—-champ-diagnostics" tabindex="-1"><code>POST /api/evaluate</code> — champ <code>diagnostics</code> <a class="header-anchor" href="#post-api-evaluate-—-champ-diagnostics" aria-label="Permalink to &quot;`POST /api/evaluate` — champ `diagnostics`&quot;">​</a></h2><ul><li><code>hadAssignedVariationInRequest</code> : <code>true</code> si <code>context.assignedVariationId</code> était un entier valide dans la requête.</li><li><code>resolvedBySticky</code> : <code>true</code> si <code>reason</code> vaut <code>by_sticky_assignment</code>.</li></ul><h2 id="stockage" tabindex="-1">Stockage <a class="header-anchor" href="#stockage" aria-label="Permalink to &quot;Stockage&quot;">​</a></h2><p>Racine des fichiers = dépôt <strong><code>abtest-campaigns-segments</code></strong> (montage selon config de déploiement).</p><p>Code : <a href="https://github.com/skhamvon/abtest-solution/blob/main/apps/api/src/server.ts" target="_blank" rel="noreferrer">apps/api/src/server.ts</a>.</p>',13)])])}const m=o(c,[["render",n]]);export{u as __pageData,m as default};
